CREATE FUNCTION "public"."validate_saved_game"() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path TO '' AS $$ DECLARE v_room_id uuid; v_table_type public.table_type; BEGIN PERFORM pg_catalog.pg_advisory_xact_lock(pg_catalog.hashtextextended(NEW.table_id::text, 0)); SELECT room_id, type INTO v_room_id, v_table_type FROM public.tables WHERE id = NEW.table_id; IF v_table_type IS DISTINCT FROM 'removable_top'::public.table_type THEN RAISE EXCEPTION 'SAVED_GAME_REQUIRES_REMOVABLE_TOP' USING ERRCODE = '23514'; END IF; IF EXISTS (SELECT 1 FROM public.event_room_blocks WHERE room_id = v_room_id AND date BETWEEN NEW.start_date AND NEW.end_date) THEN RAISE EXCEPTION 'SAVED_GAME_EVENT_CONFLICT' USING ERRCODE = '23P01'; END IF; IF NEW.status = 'active' AND EXISTS (SELECT 1 FROM public.reservations WHERE table_id = NEW.table_id AND surface = 'bottom'::public.table_surface AND status = ANY (ARRAY['pending'::public.reservation_status, 'active'::public.reservation_status]) AND date BETWEEN NEW.start_date AND NEW.end_date) THEN RAISE EXCEPTION 'SAVED_GAME_BOTTOM_RESERVATION_CONFLICT' USING ERRCODE = '23P01'; END IF; NEW.updated_at := now(); RETURN NEW; END; $$;
